{"parentUuid":"7294221d-07e7-4b83-ba50-f3d76d10fbb1","isSidechain":true,"promptId":"499753ce-636c-42a5-b58e-cd5debacd4c6","agentId":"ad56b617107df84ed","type":"user","message":{"role":"user","content":[{"tool_use_id":"REDACTED","type":"tool_result","content":"     1→#!/usr/bin/env node
     2→
     3→/**
     4→ * Playwright MCP Server
     5→ *
     6→ * Exposes Playwright browser automation and Backstop.js visual regression
     7→ * testing via the MCP protocol over HTTP.
     8→ */
     9→
    10→import http from 'node:http';
    11→import { chromium } from 'playwright';
    12→
    13→const PORT = parseInt(process.env.PORT || '3002', 10);
    14→
    15→/**
    16→ * Bearer token for authenticating incoming requests.
    17→ * Set PLAYWRIGHT_AUTH_TOKEN in the environment before starting the server.
    18→ */
    19→const AUTH_TOKEN = process.env.PLAYWRIGHT_AUTH_TOKEN;
    20→
    21→/** @type {import('playwright').Browser | null} */
    22→let browser = null;
    23→
    24→async function getBrowser() {
    25→  if (!browser || !browser.isConnected()) {
    26→    browser = await chromium.launch({
    27→      headless: true,
    28→      // TODO: Remove --no-sandbox once the container runs as a non-root user.
    29→      // The flag is required when Chromium is launched as root (default in many
    30→      // base images) but should not be used in production deployments that run
    31→      // as an unprivileged user.
    32→      args: ['--no-sandbox', '--disable-setuid-sandbox'],
    33→    });
    34→  }
    35→  return browser;
    36→}
    37→
    38→/**
    39→ * Validate a file path argument to prevent command injection.
    40→ * Rejects any path containing shell metacharacters.
    41→ *
    42→ * @param {string} value - The path value to validate.
    43→ * @returns {string} The validated path.
    44→ * @throws {Error} If the path contains disallowed characters.
    45→ */
    46→function validateConfigPath(value) {
    47→  // Reject shell metacharacters that could enable command injection
    48→  if (/[;|&$`\\'"<>(){}[\]!#~]/.test(value)) {
    49→    throw new Error(`Invalid config path: contains disallowed characters`);
    50→  }
    51→  return value;
    52→}
    53→
    54→/**
    55→ * Handle incoming tool requests
    56→ */
    57→async function handleToolCall(toolName, args) {
    58→  switch (toolName) {
    59→    case 'playwright_navigate': {
    60→      const b = await getBrowser();
    61→      const page = await b.newPage();
    62→      try {
    63→        await page.goto(args.url, { waitUntil: 'domcontentloaded', timeout: 60000 });
    64→        const title = await page.title();
    65→        const content = await page.content();
    66→        return { title, url: args.url, contentLength: content.length };
    67→      } finally {
    68→        await page.close();
    69→      }
    70→    }
    71→
    72→    case 'playwright_screenshot': {
    73→      const b = await getBrowser();
    74→      const page = await b.newPage();
    75→      try {
    76→        await page.goto(args.url, { waitUntil: 'networkidle', timeout: 60000 });
    77→        const screenshot = await page.screenshot({
    78→          fullPage: args.fullPage ?? true,
    79→          type: 'png',
    80→        });
    81→        return {
    82→          url: args.url,
    83→          format: 'png',
    84→          data: screenshot.toString('base64'),
    85→          size: screenshot.length,
    86→        };
    87→      } finally {
    88→        await page.close();
    89→      }
    90→    }
    91→
    92→    case 'backstop_reference': {
    93→      const { execFileSync } = await import('node:child_process');
    94→      const configPath = validateConfigPath(args.config || '/app/backstop.json');
    95→      const output = execFileSync('npx', ['backstop', 'reference', `--config=${configPath}`], {
    96→        encoding: 'utf-8',
    97→        timeout: 120000,
    98→        cwd: '/app',
    99→      });
   100→      return { success: true, output };
   101→    }
   102→
   103→    case 'backstop_test': {
   104→      const { execFileSync } = await import('node:child_process');
   105→      const configPath = validateConfigPath(args.config || '/app/backstop.json');
   106→      try {
   107→        const output = execFileSync('npx', ['backstop', 'test', `--config=${configPath}`], {
   108→          encoding: 'utf-8',
   109→          timeout: 120000,
   110→          cwd: '/app',
   111→        });
   112→        return { passed: true, output };
   113→      } catch (err) {
   114→        return { passed: false, output: err.stdout || err.message };
   115→      }
   116→    }
   117→
   118→    default:
   119→      return { error: `Unknown tool: ${toolName}` };
   120→  }
   121→}
   122→
   123→/**
   124→ * Authenticate a request using a Bearer token.
   125→ * Returns true if the request is authorized, false otherwise.
   126→ * The /health endpoint is intentionally exempt so orchestration infrastructure
   127→ * can monitor liveness without credentials.
   128→ *
   129→ * @param {import('node:http').IncomingMessage} req
   130→ * @returns {boolean}
   131→ */
   132→function isAuthorized(req) {
   133→  if (!AUTH_TOKEN) {
   134→    // No token configured — log a warning and allow the request so the server
   135→    // remains functional during local development, but operators should always
   136→    // set PLAYWRIGHT_AUTH_TOKEN in deployed environments.
   137→    console.error('[playwright-server] WARNING: PLAYWRIGHT_AUTH_TOKEN is not set. All requests are accepted.');
   138→    return true;
   139→  }
   140→  const authHeader = req.headers['authorization'] || '';
   141→  const match = authHeader.match(/^Bearer (.+)$/i);
   142→  return match !== null && match[1] === AUTH_TOKEN;
   143→}
   144→
   145→/**
   146→ * HTTP server for MCP tool calls and health checks
   147→ */
   148→const server = http.createServer(async (req, res) => {
   149→  // Health endpoint — exempt from auth so infrastructure probes work without credentials
   150→  if (req.method === 'GET' && req.url === '/health') {
   151→    const connected = browser?.isConnected() ?? false;
   152→    res.writeHead(200, { 'Content-Type': 'application/json' });
   153→    res.end(JSON.stringify({
   154→      status: 'ok',
   155→      service: 'playwright',
   156→      browserConnected: connected,
   157→      uptime: process.uptime(),
   158→    }));
   159→    return;
   160→  }
   161→
   162→  // All non-health endpoints require a valid Bearer token
   163→  if (!isAuthorized(req)) {
   164→    res.writeHead(401, { 'Content-Type': 'application/json' });
   165→    res.end(JSON.stringify({ error: 'Unauthorized' }));
   166→    return;
   167→  }
   168→
   169→  // Tool call endpoint
   170→  if (req.method === 'POST' && req.url === '/tool') {
   171→    let body = '';
